const items = $input.all();
const foundations = [];
for (const item of items) {
  const response = item.json;
  if (response.error || response.statusCode >= 400) continue;
  const orgs = response.organizations || response.results || [];
  for (const org of orgs) {
    const name = (org.name || '').toLowerCase();
    const isFoundation = name.includes('foundation') || name.includes('trust') || name.includes('fund');
    if (!isFoundation) continue;
    foundations.push({
      json: {
        oppNum: 'PP-' + org.ein,
        title: org.name,
        description: 'Tax-exempt organization in ' + (org.city || 'Georgia'),
        link: 'https://projects.propublica.org/nonprofits/organizations/' + org.ein,
        agency: org.name,
        source: 'ProPublica 990',
        awardFloor: 0,
        awardCeiling: 0,
        status: 'active'
      }
    });
  }
}
return foundations.length > 0 ? foundations : [{ json: { empty: true, source: 'propublica' } }];

const items = $input.all();
const grants = [];
for (const item of items) {
  const results = item.json.results || [];
  for (const award of results) {
    if (!award || parseFloat(award['Award Amount']) < 5000) continue;
    grants.push({
      json: {
        oppNum: 'USA-' + award['Award ID'],
        title: (award['Description'] || award['Recipient Name']) + ' - ' + award['Awarding Agency'],
        description: 'Federal grant awarded in Georgia.',
        link: 'https://www.usaspending.gov/award/' + encodeURIComponent(award['Award ID']),
        agency: award['Awarding Agency'],
        source: 'USAspending.gov',
        awardFloor: 0,
        awardCeiling: parseFloat(award['Award Amount']),
        status: 'active'
      }
    });
  }
}
return grants.length > 0 ? grants : [{ json: { empty: true, source: 'usaspending' } }];

