const items = $input.all();
const codeItems = $('Code in JavaScript5').all();
let allGrants = [];

items.forEach((item, index) => {
  const grant = codeItems[index]?.json.grant || {};
  const aiText = item.json?.output?.[0]?.content?.[0]?.text || '';

  // Parse AI response for eligible org IDs
  let eligible = { eligible_org_ids: [], reason: '' };
  try {
    const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    eligible = JSON.parse(cleaned);
  } catch (e) {
    // If parse fails, include all orgs from the original data
    const orgs = codeItems[index]?.json.orgs || [];
    eligible.eligible_org_ids = orgs.map(o => o.id);
    eligible.reason = 'AI parse failed, defaulting to all orgs';
  }

  if (!Array.isArray(eligible.eligible_org_ids) || eligible.eligible_org_ids.length === 0) return;

  const description = grant.description || '';

  const descriptionHtml = `<div><h3>Grant Opportunity</h3>` +
    `<p><strong>Source:</strong> ${grant.source}</p>` +
    `<p><strong>Agency:</strong> ${grant.agency}</p>` +
    `<p><strong>Type:</strong> ${grant.grant_type || 'unknown'}</p>` +
    (grant.grant_state ? `<p><strong>State:</strong> ${grant.grant_state}</p>` : '') +
    `<p><strong>Award Range:</strong> $${grant.awardFloor || 0} - $${grant.awardCeiling || 0}</p>` +
    `<p><strong>Open Date:</strong> ${grant.openDate}</p>` +
    `<p><strong>Deadline:</strong> ${grant.closeDate}</p>` +
    `<hr><h4>Description:</h4>` +
    `<p>${description}</p>` +
    `<p><em>Relevance: ${grant.relevance_reason || 'N/A'}</em></p>` +
    `<hr>` +
    `<p><strong>Matched Keywords:</strong> ${Array.isArray(grant.matchedKeywords) ? grant.matchedKeywords.join(', ') : (grant.matchedKeywords || '')}</p>` +
    `<p><a href=\"${grant.source_url}\">View Original Listing</a></p>` +
    `</div>`;

  let deadlineValue = null;
  if (grant.closeDate && grant.closeDate !== 'See listing' && grant.closeDate !== 'Not specified') {
    const parsed = new Date(grant.closeDate);
    if (!isNaN(parsed.getTime())) {
      const yyyy = parsed.getUTCFullYear();
      const mm = String(parsed.getUTCMonth() + 1).padStart(2, '0');
      const dd = String(parsed.getUTCDate()).padStart(2, '0');
      deadlineValue = `${yyyy}-${mm}-${dd}T00:00:00.000Z`;
    } else {
      deadlineValue = grant.closeDate;
    }
  }

  for (const orgId of eligible.eligible_org_ids) {
    allGrants.push({
      org_id: orgId,
      title: grant.title || '',
      funder_name: grant.agency || null,
      description: description,
      amount: grant.awardCeiling > 0 ? grant.awardCeiling : null,
      deadline: deadlineValue,
      stage: 'discovery',
      source: grant.source || 'Grant Scanner',
      source_id: grant.source_id,
      source_url: grant.source_url,
      metadata: {
        grants_gov_id: grant.id,
        agency_code: grant.agencyCode,
        open_date: grant.openDate,
        award_floor: grant.awardFloor,
        award_ceiling: grant.awardCeiling,
        matched_keywords: grant.matchedKeywords,
        relevance_score: grant.relevanceScore,
        grant_type: grant.grant_type || 'unknown',
        grant_state: grant.grant_state || null,
        relevance_reason: grant.relevance_reason || '',
        location_filter_reason: eligible.reason || '',
        priority: 'medium',
        description_html: descriptionHtml
      }
    });
  }
});

if (allGrants.length === 0) {
  return [{ json: { noRelevantGrants: true, message: 'No eligible grants after location filtering' } }];
}

