    results.push({
      json: {
        error: "No valid HTML received",
        receivedType: typeof html,
        length: html?.length || 0
      }
    });
    continue;
  }

  // Normalize whitespace and remove script/style tags to make regex more reliable
  html = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
             .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
             .replace(/\s+/g, ' ');

  // Find the "Upcoming Funding Opportunity" heading and grab content until next major section
  // We look for the h3/p with "Upcoming" then the following card with h4 + paragraphs
  const sectionRegex = /<h3[^>]*>Active Funding Opportunities<\/h3>[\s\S]*?<p[^>]*><span[^>]*>Upcoming Funding Opportunity<\/span><\/p>[\s\S]*?(<div class="card image[^>]*>[\s\S]*?<div class="cmp-customcard[^>]*>[\s\S]*?<\/div>)/i;

  const sectionMatch = sectionRegex.exec(html);
  if (!sectionMatch) {
    results.push({
      json: {
        empty: true,
        message: "No 'Upcoming Funding Opportunity' section found in HTML",
        hint: "Content may be loaded dynamically via JavaScript → check Network tab for JSON calls"
      }
    });
    continue;
  }

  const cardHtml = sectionMatch[1];

  // Extract title (h4 with heading8-style or similar)
  const titleMatch = cardHtml.match(/<h4[^>]*class="[^"]*heading8-style[^"]*"[^>]*>([\s\S]*?)<\/h4>/i);
  const title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g, '').trim() : "No title found";

  // Extract all <p> paragraphs in the card (description + release date)
  const descParagraphs = [];
  const pRegex = /<p[^>]*>([\s\S]*?)<\/p>/gi;
  let pMatch;
  while ((pMatch = pRegex.exec(cardHtml)) !== null) {
    let text = pMatch[1]
      .replace(/<[^>]+>/g, '')          // strip inner tags
      .replace(/&nbsp;/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
    if (text && text.length > 10) {      // ignore very short/empty
      descParagraphs.push(text);
    }
  }

  // Look for bold release date specifically
  const releaseMatch = cardHtml.match(/<b>Release date:\s*([^<]+)<\/b>/i);
  const releaseDate = releaseMatch ? releaseMatch[1].trim() : "Not found";

  // Build clean output
  results.push({
    json: {
      section: "Upcoming Funding Opportunity",
      title: title,
