const keywords = [
  'foster care',
  'foster youth',
  'youth transition',
  'aging out',
  'senior',
  'elderly',
  'aging',
  'older adults',
  'african american',
  'black community',
  'minority',
  'underserved',
  'nonprofit capacity',
  'organizational development',
  'capacity building',
  'georgia',
  'community development',
  'social services',
  'human services',
  'family services',
  'youth development',
  'community foundation',
  'health and human services',
  'child welfare',
  'independent living'
];

for (const item of items) {
  const grant = item.json;

  // Filter by amount range: $5,000 - $100,000
  // Include if awardCeiling is 0 (unknown) or within range
  const meetsAmountCriteria = 
    grant.awardCeiling === 0 || 
    (grant.awardCeiling >= 5000 && grant.awardFloor <= 100000);

  if (!meetsAmountCriteria) continue;

  // Combine title and description for keyword search
  const searchText = (grant.title + ' ' + grant.description + ' ' + grant.category + ' ' + grant.agency).toLowerCase();

  // Find matching keywords
  const matchedKeywords = keywords.filter(function(kw) { return searchText.includes(kw); });

  // Include if matches at least one keyword OR is from ProPublica (already filtered)
  if (matchedKeywords.length > 0 || grant.source === 'ProPublica 990') {
    qualifiedGrants.push({
      json: {
        id: grant.id,
        oppNum: grant.oppNum,
        title: grant.title,
        description: grant.description,
        link: grant.link,
        openDate: grant.openDate,
        closeDate: grant.closeDate,
