parameters.jsCode:
// Extract grants from USAspending API response
const items = $input.all();
const grants = [];

for (const item of items) {
  const response = item.json;

  let results = [];
  if (response.results) {
    results = response.results;
  } else if (Array.isArray(response)) {
    results = response;
  }

  for (const award of results) {
    if (!award) continue;

    const awardAmount = parseFloat(award['Award Amount']) || 0;

    // Filter to reasonable grant amounts for nonprofits
    if (awardAmount < 5000 || awardAmount > 500000) continue;

    const oppNum = 'USA-' + (award['Award ID'] || Date.now() + '-' + Math.random().toString(36).substr(2, 5));

    grants.push({
      json: {
        id: award['Award ID'] || oppNum,
        oppNum: oppNum,
        title: (award['Description'] || award['Recipient Name'] || 'Federal Grant') + ' - ' + (award['Awarding Sub Agency'] || award['Awarding Agency'] || ''),
        description: 'Federal grant awarded in Georgia. Agency: ' + (award['Awarding Agency'] || 'N/A') + '. This indicates active funding in this program area.',
        link: 'https://www.usaspending.gov/award/' + encodeURIComponent(award['Award ID'] || ''),
        openDate: award['Start Date'] || '',
        closeDate: award['End Date'] || 'See agency',
        agency: award['Awarding Agency'] || award['Awarding Sub Agency'] || '',
        agencyCode: award['cfda_number'] || '',
        category: award['Award Type'] || 'Grant',
        source: 'USAspending.gov',
        awardFloor: Math.floor(awardAmount * 0.5),
        awardCeiling: Math.ceil(awardAmount * 1.5),
        status: 'active'
      }
    });
  }
}

return grants.length > 0 ? grants : [{ json: { empty: true, source: 'usaspending' } }];

// Extract CFDA programs as potential grant sources
const items = $input.all();
const programs = [];

for (const item of items) {
  const response = item.json;

  let results = response.results || [];

  for (const prog of results) {
    if (!prog || !prog.cfda_number) continue;

    const oppNum = 'CFDA-' + prog.cfda_number;

    programs.push({
      json: {
        id: prog.cfda_number,
        oppNum: oppNum,
        title: prog.program_title || 'CFDA ' + prog.cfda_number,
        description: 'Federal assistance program. Search Grants.gov for current opportunities under CFDA ' + prog.cfda_number,
        link: 'https://sam.gov/fal/' + prog.cfda_number.replace('.', '') + '/view',
        openDate: new Date().toISOString().split('T')[0],
        closeDate: 'Ongoing - Check Grants.gov',
        agency: prog.agency_name || 'Federal Agency',
        agencyCode: prog.cfda_number,
        category: 'Federal Program',
        source: 'CFDA Directory',
        awardFloor: 0,
        awardCeiling: 0,
        status: 'active'
      }
    });
  }
}

return programs.length > 0 ? programs : [{ json: { empty: true, source: 'cfda' } }];

// Parse Georgia Grants Management portal HTML
const items = $input.all();
const grants = [];

for (const item of items) {
  const html = item.json.data || item.json.body || item.json;

  if (typeof html !== 'string') continue;

  // Look for grant opportunity patterns in HTML
  const linkPatterns = html.match(/<a[^>]*href="([^"]*grant[^"]*)"[^>]*>([^<]+)<\/a>/gi) || [];

  // Extract from links
  for (const linkHtml of linkPatterns) {
    const hrefMatch = linkHtml.match(/href="([^"]+)"/);
    const textMatch = linkHtml.match(/>([^<]+)</);

    if (!textMatch || !textMatch[1]) continue;

    const title = textMatch[1].trim();
    if (title.length < 10) continue; // Skip short links

    const oppNum = 'GA-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);
    let link = hrefMatch ? hrefMatch[1] : '';
    if (link && !link.startsWith('http')) {
      link = 'https://grantsmanagement.georgia.gov' + (link.startsWith('/') ? '' : '/') + link;
    }

    grants.push({
      json: {
        id: oppNum,
        oppNum: oppNum,
        title: 'Georgia: ' + title,
        description: 'State of Georgia grant opportunity. Visit the Georgia Grants Management portal for details.',
        link: link || 'https://grantsmanagement.georgia.gov/grants',
        openDate: new Date().toISOString().split('T')[0],
        closeDate: 'See state portal',
        agency: 'State of Georgia',
        agencyCode: 'GA',
        category: 'State Grant',
        source: 'Georgia Grants Portal',
        awardFloor: 0,
        awardCeiling: 0,
        status: 'posted'
      }
    });
  }
}

return grants.length > 0 ? grants : [{ json: { empty: true, source: 'georgia-portal' } }];
